-- UcMarket MVP mock data for user/auth and market development.
-- Safe to rerun: this script only deletes rows whose UUIDs use the mock prefixes below.
-- All mock users share the BCrypt password: password

BEGIN;

-- Remove prior mock rows in dependency order.
DELETE FROM admin_logs WHERE id::text LIKE '00000000-0000-4011-8000-%';
DELETE FROM notifications WHERE id::text LIKE '00000000-0000-4009-8000-%';
DELETE FROM user_portfolio_snapshots WHERE id::text LIKE '00000000-0000-4010-8000-%';
DELETE FROM wallet_transactions WHERE id::text LIKE '00000000-0000-4008-8000-%';
