    ('00000000-0000-4003-8000-000000000001', 'MKT-0001', '00000000-0000-4000-8000-000000000003', '台北 2026-06-05 會下雨嗎？', '以中央氣象署台北測站當日是否有降雨紀錄為準。', 'WEATHER', 'BINARY', 'https://www.cwa.gov.tw/', '若 2026-06-05 台北測站任一小時降雨量大於 0mm，結果為 YES，否則為 NO。', '2026-06-05 23:59:59', 'ACTIVE', NULL, NULL, 1680.00, 1320.00, '2026-05-29 14:00:00', '00000000-0000-4000-8000-000000000001', NULL, NULL, '2026-05-29 09:30:00', '2026-05-29 14:00:00'),
    ('00000000-0000-4003-8000-000000000002', 'MKT-0002', '00000000-0000-4000-8000-000000000004', '美國 2026 年 6 月 CPI 年增率會低於 3% 嗎？', '以美國 BLS 公布之 CPI-U 年增率為準。', 'ECONOMY', 'BINARY', 'https://www.bls.gov/cpi/', 'BLS 首次公布的 2026 年 6 月 CPI-U year-over-year 數值低於 3.0% 則 YES。', '2026-07-15 20:30:00', 'PENDING', NULL, NULL, 100.00, 100.00, NULL, NULL, NULL, NULL, '2026-06-01 10:00:00', '2026-06-01 10:20:00'),
    ('00000000-0000-4003-8000-000000000003', 'MKT-0003', '00000000-0000-4000-8000-000000000006', '下一場 Apple 發表會會公布新款 iPad 嗎？', '以 Apple 官方發表會頁面與新聞稿為準。', 'TECH', 'BINARY', 'https://www.apple.com/newsroom/', '若下一場 Apple Special Event 官方新聞稿明確提到新款 iPad 產品，結果為 YES。', '2026-09-30 23:59:59', 'DRAFT', NULL, NULL, 100.00, 100.00, NULL, NULL, NULL, NULL, '2026-06-01 11:30:00', '2026-06-01 11:30:00'),
    ('00000000-0000-4003-8000-000000000004', 'MKT-0004', '00000000-0000-4000-8000-000000000005', '中職 2026 上半季冠軍會是兄弟嗎？', '以中華職棒官方戰績公告為準。', 'SPORTS', 'BINARY', 'https://www.cpbl.com.tw/', '若中華職棒 2026 上半季冠軍隊伍為中信兄弟，結果為 YES。', '2026-06-30 23:59:59', 'ACTIVE', NULL, NULL, 1210.00, 1890.00, '2026-05-30 16:00:00', '00000000-0000-4000-8000-000000000001', NULL, NULL, '2026-05-30 10:10:00', '2026-05-30 16:00:00'),
    ('00000000-0000-4003-8000-000000000005', 'MKT-0005', '00000000-0000-4000-8000-000000000007', '台中 2026-06-03 最高溫會達到 35 度嗎？', '以中央氣象署台中測站日最高溫為準。', 'WEATHER', 'BINARY', 'https://www.cwa.gov.tw/', '若 2026-06-03 台中測站日最高溫 >= 35.0 攝氏度，結果為 YES。', '2026-06-03 23:59:59', 'REJECTED', NULL, NULL, 100.00, 100.00, NULL, NULL, NULL, NULL, '2026-05-31 09:00:00', '2026-05-31 15:00:00'),
    ('00000000-0000-4003-8000-000000000006', 'MKT-0006', '00000000-0000-4000-8000-000000000010', 'BTC 在 2026-06-01 會收高於 100,000 美元嗎？', '以 CoinMarketCap UTC 日收盤價為準。', 'CRYPTO', 'BINARY', 'https://coinmarketcap.com/currencies/bitcoin/', '若 CoinMarketCap 顯示 BTC 2026-06-01 UTC close price > 100000，結果為 YES。', '2026-06-01 23:59:59', 'RESOLVED', 'NO', NULL, 2150.00, 2860.00, '2026-05-27 13:00:00', '00000000-0000-4000-8000-000000000002', '2026-06-02 01:00:00', '00000000-0000-4000-8000-000000000002', '2026-05-27 09:00:00', '2026-06-02 01:00:00'),
    ('00000000-0000-4003-8000-000000000007', 'MKT-0007', '00000000-0000-4000-8000-000000000004', 'NASDAQ 100 本週會創新高嗎？', '以 Nasdaq 官方收盤資料為準。', 'ECONOMY', 'BINARY', 'https://www.nasdaq.com/', '若本週任一交易日 NDX 收盤價高於此前歷史收盤高點，結果為 YES。', '2026-06-07 23:59:59', 'CLOSED', NULL, NULL, 1820.00, 1740.00, '2026-05-28 12:00:00', '00000000-0000-4000-8000-000000000001', NULL, NULL, '2026-05-28 08:30:00', '2026-06-01 00:00:00'),
    ('00000000-0000-4003-8000-000000000008', 'MKT-0008', '00000000-0000-4000-8000-000000000006', 'OpenAI 今年會釋出新的公開 API 重大版本嗎？', '以 OpenAI 官方文件或公告為準。', 'TECH', 'BINARY', 'https://platform.openai.com/docs', '若 2026 年內 OpenAI 官方公告新的 API 重大版本或新世代模型 API，結果為 YES。', '2026-12-31 23:59:59', 'ACTIVE', NULL, NULL, 2400.00, 1600.00, '2026-05-29 18:00:00', '00000000-0000-4000-8000-000000000002', NULL, NULL, '2026-05-29 12:45:00', '2026-05-29 18:00:00'),
    ('00000000-0000-4003-8000-000000000009', 'MKT-0009', '00000000-0000-4000-8000-000000000003', '桃園機場捷運 2026-06-10 會準點率高於 95% 嗎？', '以桃園捷運官方營運公告為準。', 'TRANSPORT', 'BINARY', 'https://www.tymetro.com.tw/', '若官方公布 2026-06-10 準點率 > 95%，結果為 YES。', '2026-06-10 23:59:59', 'CANCELED', NULL, NULL, 100.00, 100.00, NULL, NULL, NULL, NULL, '2026-05-31 14:00:00', '2026-06-01 09:00:00'),
